import React, { useState, useEffect } from "react";
import RouteForm from "./components/RouteForm";
import TripForm from "./components/TripForm";
import RouteTable from "./components/RouteTable";

function App() {
  const [routes, setRoutes] = useState([]);
  const [trips, setTrips] = useState([]);
  const [trains, setTrains] = useState([]);

  // Загружаем существующие данные с сервера
  useEffect(() => {
    fetch("http://localhost:5050/routes")
      .then(res => res.json())
      .then(setRoutes)
      .catch(console.error);

    fetch("http://localhost:5050/trips")
      .then(res => res.json())
      .then(setTrips)
      .catch(console.error);

    fetch("http://localhost:5050/trains")
      .then(res => res.json())
      .then(setTrains)
      .catch(console.error);
  }, []);

  // Функция для получения номера поезда по id
  const getTrainNumber = (trainId) => {
    const train = trains.find(t => t.id === trainId);
    return train ? train.number : trainId;
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h1>Прототип ПК/ПАК — маршруты, поезда и рейсы</h1>

      <div style={{ marginBottom: "30px" }}>
        <RouteForm onNewRoute={(route) => setRoutes(prev => [...prev, route])} />
      </div>

      <div style={{ marginBottom: "30px" }}>
        <TripForm onNewTrip={(trip) => setTrips(prev => [...prev, trip])} />
      </div>

      <div>
        <RouteTable 
          routes={routes} 
          trips={trips} 
          getTrainNumber={getTrainNumber} 
        />
      </div>
    </div>
  );
}

export default App;
